import { api } from '@semparar/mf-app-user';
import type { GetMarketplaceResponse, MarketplaceParams } from '../models';

class MarketplaceApi {
  async getMarketplace(params: MarketplaceParams): Promise<GetMarketplaceResponse> {
    const urlParams = new URLSearchParams(params);
    const response = await api.get<GetMarketplaceResponse>(
      `/marketplace/v1/marketplace/getToken?${urlParams.toString()}`
    );
    return response.data;
  }
}

export const marketplaceApi = new MarketplaceApi();

